//! `baton-get` — download iRODS data objects.
//!
//! Inline mode (default): each input line names a data object, and
//! the output line is the same record with the bytes base64-encoded
//! on the `data` field.
//!
//! `--save` mode: streams bytes from iRODS into
//! `<input.directory>/<input.data_object>` on the local filesystem
//! and emits the input record back unchanged (no inline `data`).
//! Each input record must include a `directory` field; missing
//! directories surface as in-band per-record errors. The directory
//! must already exist — baton-rs follows upstream baton in not
//! auto-creating destinations.

use std::io::{BufRead, Write};
use std::time::Duration;

use anyhow::{Context, Result};
use baton_rs::operations::get::{self, GetOptions};
use baton_rs::{
    parse_connect_time, ReconnectingSession, RodsConnection, Target,
    DEFAULT_CONNECT_TIME_SECS,
};
use clap::Parser;
use tracing_subscriber::EnvFilter;

#[derive(Parser, Debug)]
#[command(name = "baton-get", about = "Download iRODS data objects")]
struct Args {
    /// Save bytes to `<directory>/<data_object>` on the local
    /// filesystem instead of returning them inline as base64. Each
    /// input record must include a `directory` field.
    #[arg(long)]
    save: bool,

    /// Wall-clock seconds before the iRODS connection is torn down
    /// and rebuilt between input records. Default 600 (10 min);
    /// minimum 10. Matches upstream baton's --connect-time / -c.
    #[arg(
        short = 'c',
        long,
        default_value_t = DEFAULT_CONNECT_TIME_SECS,
        value_parser = parse_connect_time
    )]
    connect_time: u64,

    /// Verbose logging (DEBUG level).
    #[arg(short, long, conflicts_with = "silent")]
    verbose: bool,

    /// Silent logging (ERROR level only).
    #[arg(long)]
    silent: bool,
}

impl Args {
    fn to_options(&self) -> GetOptions {
        GetOptions { save: self.save }
    }

    fn log_level(&self) -> &'static str {
        if self.silent {
            "error"
        } else if self.verbose {
            "debug"
        } else {
            "info"
        }
    }
}

fn init_tracing(args: &Args) {
    let filter = EnvFilter::try_from_default_env()
        .unwrap_or_else(|_| EnvFilter::new(args.log_level()));
    tracing_subscriber::fmt()
        .with_env_filter(filter)
        .with_writer(std::io::stderr)
        .init();
}

fn main() -> Result<()> {
    let args = Args::parse();
    init_tracing(&args);

    let opts = args.to_options();

    let mut conn = RodsConnection::connect_from_env().context("connecting to iRODS")?;
    conn.login_from_auth_file().context("authenticating")?;
    let mut session =
        ReconnectingSession::new(conn, Duration::from_secs(args.connect_time));

    let stdin = std::io::stdin();
    let stdout = std::io::stdout();
    let mut out = stdout.lock();

    for line in stdin.lock().lines() {
        let line = line.context("reading stdin")?;
        if line.trim().is_empty() {
            continue;
        }

        // Reconnect at record boundaries when the wall-clock watchdog
        // says it's time. Reconnect failures are fail-fast — there's
        // no useful in-band annotation when the connection itself is
        // broken.
        let conn = session.maybe_reconnect().context("reconnecting to iRODS")?;

        let target: Target =
            serde_json::from_str(&line).context("parsing input line as a Target")?;

        // iRODS-side failures per input are annotated in-band and the
        // stream keeps going. Parse / IO errors above are still
        // fail-fast — we can't annotate something we couldn't parse.
        let output = get::get_one_annotated(conn, target, &opts);

        serde_json::to_writer(&mut out, &output).context("writing output line")?;
        writeln!(&mut out).context("writing newline")?;
    }

    Ok(())
}
